import{_ as i,C as l,o as a,c as t,a2 as s,b as o,w as r,a as p,E as d,a3 as c}from"./chunks/framework._l9dR58Y.js";const E=JSON.parse('{"title":"第一章：Superpowers 简介","description":"","frontmatter":{},"headers":[],"relativePath":"chapter-01.md","filePath":"chapter-01.md","lastUpdated":1774633865000}'),u={name:"chapter-01.md"};function h(b,e,g,m,k,v){const n=l("Mermaid");return a(),t("div",null,[e[1]||(e[1]=s(`<h1 id="第一章-superpowers-简介" tabindex="-1">第一章：Superpowers 简介 <a class="header-anchor" href="#第一章-superpowers-简介" aria-label="Permalink to &quot;第一章：Superpowers 简介&quot;">​</a></h1><h2 id="什么是-superpowers" tabindex="-1">什么是 Superpowers？ <a class="header-anchor" href="#什么是-superpowers" aria-label="Permalink to &quot;什么是 Superpowers？&quot;">​</a></h2><p>Superpowers 是一套为 AI 编码代理打造的完整软件开发工作流系统。它基于一组可组合的&quot;技能&quot;（skills）构建，通过初始指令确保你的代理能够正确使用这些技能。</p><p>简单来说，Superpowers 让你的 AI 编码代理变得更聪明、更可靠、更高效。</p><h2 id="核心理念" tabindex="-1">核心理念 <a class="header-anchor" href="#核心理念" aria-label="Permalink to &quot;核心理念&quot;">​</a></h2><p>传统的 AI 编码代理往往存在一些问题：</p><ul><li><strong>直接跳入编码</strong>：没有经过充分的思考和规划</li><li><strong>缺乏系统性</strong>：随机试错而不是系统化调试</li><li><strong>忽视测试</strong>：先写代码再补测试，甚至不写测试</li><li><strong>复杂度失控</strong>：过度设计，写了很多不必要的代码</li><li><strong>缺乏验证</strong>：声称完成了，但实际并未真正解决问题</li></ul><p>Superpowers 通过强制的工作流程来解决这些问题。</p><h2 id="工作原理" tabindex="-1">工作原理 <a class="header-anchor" href="#工作原理" aria-label="Permalink to &quot;工作原理&quot;">​</a></h2><p>Superpowers 的工作流程从你启动编码代理的那一刻就开始了。</p><h3 id="_1-需求澄清" tabindex="-1">1. 需求澄清 <a class="header-anchor" href="#_1-需求澄清" aria-label="Permalink to &quot;1. 需求澄清&quot;">​</a></h3><p>当代理看到你要构建某些东西时，它<strong>不会</strong>立即尝试编写代码。相反，它会退一步，询问你真正想要做什么。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户：帮我写一个用户登录功能</span></span>
<span class="line"><span>代理：好的，在我们开始编码之前，让我先了解一些细节...</span></span>
<span class="line"><span>      - 这个登录功能支持哪些登录方式？（用户名/密码、OAuth、手机验证码？）</span></span>
<span class="line"><span>      - 需要记住登录状态吗？持续多久？</span></span>
<span class="line"><span>      - 密码有什么复杂度要求吗？</span></span>
<span class="line"><span>      - 需要登录失败次数限制吗？</span></span>
<span class="line"><span>      ...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><h3 id="_2-规格设计" tabindex="-1">2. 规格设计 <a class="header-anchor" href="#_2-规格设计" aria-label="Permalink to &quot;2. 规格设计&quot;">​</a></h3><p>一旦从对话中提取出了规格说明，代理会将其分成足够短的片段展示给你，让你能够真正阅读和消化。</p><p>这确保了你理解并认可将要构建的内容，避免了方向性的错误。</p><h3 id="_3-实施计划" tabindex="-1">3. 实施计划 <a class="header-anchor" href="#_3-实施计划" aria-label="Permalink to &quot;3. 实施计划&quot;">​</a></h3><p>在你批准设计后，代理会制定一个实施计划。这个计划足够清晰，以至于一个热情但缺乏判断力、没有项目背景、厌恶测试的初级工程师也能遵循。</p><p>计划强调：</p><ul><li><strong>真正的红/绿 TDD</strong>（测试驱动开发）</li><li><strong>YAGNI</strong>（你不会需要它）</li><li><strong>DRY</strong>（不要重复自己）</li></ul><h3 id="_4-子代理驱动开发" tabindex="-1">4. 子代理驱动开发 <a class="header-anchor" href="#_4-子代理驱动开发" aria-label="Permalink to &quot;4. 子代理驱动开发&quot;">​</a></h3><p>一旦你说&quot;开始&quot;，代理会启动一个 <em>subagent-driven-development</em>（子代理驱动开发）进程：</p><ol><li>为每个工程任务分配一个独立的子代理</li><li>子代理执行任务</li><li>主代理审查工作成果</li><li>继续推进</li></ol><p>通常，Claude 可以自主工作数小时而不会偏离你们一起制定的计划。</p><h3 id="_5-持续验证" tabindex="-1">5. 持续验证 <a class="header-anchor" href="#_5-持续验证" aria-label="Permalink to &quot;5. 持续验证&quot;">​</a></h3><p>在整个过程中，代理会：</p><ul><li>在声称完成之前运行验证命令</li><li>确保测试通过</li><li>检查代码质量</li><li>验证是否符合原始计划</li></ul><h2 id="核心价值观" tabindex="-1">核心价值观 <a class="header-anchor" href="#核心价值观" aria-label="Permalink to &quot;核心价值观&quot;">​</a></h2><p>Superpowers 建立在以下核心价值观之上：</p><h3 id="测试驱动开发" tabindex="-1">测试驱动开发 <a class="header-anchor" href="#测试驱动开发" aria-label="Permalink to &quot;测试驱动开发&quot;">​</a></h3><p><strong>永远先写测试</strong>。这不是建议，是强制要求。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>❌ 错误：先写代码，再补测试</span></span>
<span class="line"><span>✅ 正确：先写失败测试，看它失败，写最小代码，看它通过</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="系统化优于随机" tabindex="-1">系统化优于随机 <a class="header-anchor" href="#系统化优于随机" aria-label="Permalink to &quot;系统化优于随机&quot;">​</a></h3><p>使用系统化的流程，而不是随机猜测。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>❌ 错误：试试这个...不行，试试那个...也不行...</span></span>
<span class="line"><span>✅ 正确：重现问题 → 分析根本原因 → 制定修复计划 → 验证修复</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="简化为首要目标" tabindex="-1">简化为首要目标 <a class="header-anchor" href="#简化为首要目标" aria-label="Permalink to &quot;简化为首要目标&quot;">​</a></h3><p>复杂性是敌人。简单性应该作为主要目标。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>❌ 错误：让我们为未来的需求预留扩展点</span></span>
<span class="line"><span>✅ 正确：YAGNI - 你不会需要它。只写现在需要的功能</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="证据优于声明" tabindex="-1">证据优于声明 <a class="header-anchor" href="#证据优于声明" aria-label="Permalink to &quot;证据优于声明&quot;">​</a></h3><p>在宣布成功之前，验证它确实工作。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>❌ 错误：我觉得应该修好了</span></span>
<span class="line"><span>✅ 正确：运行测试，确认输出，验证修复</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="主要功能" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能" aria-label="Permalink to &quot;主要功能&quot;">​</a></h2><h3 id="🎯-自动触发" tabindex="-1">🎯 自动触发 <a class="header-anchor" href="#🎯-自动触发" aria-label="Permalink to &quot;🎯 自动触发&quot;">​</a></h3><p>你不需要做任何特殊操作。技能会自动触发。你的编码代理只是有了 Superpowers。</p><h3 id="📚-技能库" tabindex="-1">📚 技能库 <a class="header-anchor" href="#📚-技能库" aria-label="Permalink to &quot;📚 技能库&quot;">​</a></h3><p>Superpowers 包含丰富的技能库：</p><p><strong>测试相关</strong></p><ul><li><code>test-driven-development</code> - 红-绿-重构循环</li></ul><p><strong>调试相关</strong></p><ul><li><code>systematic-debugging</code> - 四阶段根本原因分析流程</li><li><code>verification-before-completion</code> - 确保真正修复完成</li></ul><p><strong>协作相关</strong></p><ul><li><code>brainstorming</code> - 苏格拉底式设计细化</li><li><code>writing-plans</code> - 详细的实施计划</li><li><code>executing-plans</code> - 带检查点的批量执行</li><li><code>dispatching-parallel-agents</code> - 并发子代理工作流</li><li><code>requesting-code-review</code> - 预审查检查清单</li><li><code>receiving-code-review</code> - 响应反馈</li><li><code>using-git-worktrees</code> - 并行开发分支</li><li><code>finishing-a-development-branch</code> - 合并/PR 决策工作流</li><li><code>subagent-driven-development</code> - 快速迭代与双阶段审查</li></ul><p><strong>元技能</strong></p><ul><li><code>writing-skills</code> - 创建新技能的最佳实践</li><li><code>using-superpowers</code> - 技能系统介绍</li></ul><h2 id="基本工作流" tabindex="-1">基本工作流 <a class="header-anchor" href="#基本工作流" aria-label="Permalink to &quot;基本工作流&quot;">​</a></h2><p>Superpowers 定义了一个标准的开发工作流：</p>`,56)),(a(),o(c,null,{default:r(()=>[d(n,{id:"mermaid-300",class:"mermaid",graph:"graph%20TD%0A%20%20%20%20A%5B%E9%9C%80%E6%B1%82%5D%20--%3E%20B%5Bbrainstorming%3Cbr%2F%3E%E5%A4%B4%E8%84%91%E9%A3%8E%E6%9A%B4%5D%0A%20%20%20%20B%20--%3E%20C%5Busing-git-worktrees%3Cbr%2F%3E%E5%88%9B%E5%BB%BA%E5%B7%A5%E4%BD%9C%E6%A0%91%5D%0A%20%20%20%20C%20--%3E%20D%5Bwriting-plans%3Cbr%2F%3E%E7%BC%96%E5%86%99%E8%AE%A1%E5%88%92%5D%0A%20%20%20%20D%20--%3E%20E%5Bsubagent-driven-development%3Cbr%2F%3E%E6%89%A7%E8%A1%8C%E8%AE%A1%E5%88%92%5D%0A%20%20%20%20E%20--%3E%20F%5Btest-driven-development%3Cbr%2F%3ETDD%E5%BC%80%E5%8F%91%5D%0A%20%20%20%20F%20--%3E%20G%5Brequesting-code-review%3Cbr%2F%3E%E4%BB%A3%E7%A0%81%E5%AE%A1%E6%9F%A5%5D%0A%20%20%20%20G%20--%3E%20H%5Bfinishing-a-development-branch%3Cbr%2F%3E%E5%AE%8C%E6%88%90%E5%88%86%E6%94%AF%5D%0A"})]),fallback:r(()=>[...e[0]||(e[0]=[p(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=s('<p>每个阶段都有对应的技能自动触发，确保流程的正确执行。</p><h2 id="谁在使用-superpowers" tabindex="-1">谁在使用 Superpowers？ <a class="header-anchor" href="#谁在使用-superpowers" aria-label="Permalink to &quot;谁在使用 Superpowers？&quot;">​</a></h2><p>Superpowers 适用于所有使用 AI 编码代理的开发者：</p><ul><li><strong>个人开发者</strong>：提升个人开发效率和代码质量</li><li><strong>团队</strong>：统一开发流程，确保代码质量一致</li><li><strong>企业</strong>：标准化 AI 辅助开发，降低风险</li></ul><h2 id="社区与支持" tabindex="-1">社区与支持 <a class="header-anchor" href="#社区与支持" aria-label="Permalink to &quot;社区与支持&quot;">​</a></h2><p>Superpowers 是一个开源项目，由 <a href="https://blog.fsck.com" target="_blank" rel="noreferrer">Jesse Vincent</a> 和 <a href="https://primeradiant.com" target="_blank" rel="noreferrer">Prime Radiant</a> 团队构建。</p><ul><li><strong>Discord 社区</strong>：<a href="https://discord.gg/Jd8Vphy9jq" target="_blank" rel="noreferrer">加入 Discord</a></li><li><strong>GitHub Issues</strong>：<a href="https://github.com/obra/superpowers/issues" target="_blank" rel="noreferrer">https://github.com/obra/superpowers/issues</a></li><li><strong>市场</strong>：<a href="https://github.com/obra/superpowers-marketplace" target="_blank" rel="noreferrer">https://github.com/obra/superpowers-marketplace</a></li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>在下一章中，我们将学习如何在不同的平台上安装和配置 Superpowers，包括：</p><ul><li>Claude Code</li><li>Cursor</li><li>Codex</li><li>OpenCode</li><li>Gemini CLI</li></ul><hr><h2 id="参考资源" tabindex="-1">参考资源 <a class="header-anchor" href="#参考资源" aria-label="Permalink to &quot;参考资源&quot;">​</a></h2><ul><li><a href="https://blog.fsck.com/2025/10/09/superpowers/" target="_blank" rel="noreferrer">Superpowers 官方博客</a></li><li><a href="https://github.com/obra/superpowers" target="_blank" rel="noreferrer">GitHub 仓库</a></li><li><a href="https://github.com/sponsors/obra" target="_blank" rel="noreferrer">赞助开源工作</a></li></ul>',13))])}const q=i(u,[["render",h]]);export{E as __pageData,q as default};
